    }

    setIsProcessing(true);
    setProcessingStep("AUTENTICANDO ACCESO VIP...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Registro de Ingreso Club", 1);

      doc.setFontSize(11);
      doc.setTextColor(0, 0, 0);
      doc.text("1. DATOS DEL INVITADO", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 12;

      const data = [
        ["Nombre Completo:", formData.fullName],
        ["Nombre Artístico:", formData.artisticName || "N/A"],
        ["Documento:", `${formData.documentType} ${formData.documentNumber}`],
        ["Hora de Entrada:", getFullTimestamp()]
      ];

      data.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold");
        doc.text(label, 25, y);
        doc.setFont("helvetica", "normal");
        doc.text(value, 70, y);
        y += 8;
      });

      y += 10;
      doc.setFont("helvetica", "bold");
      doc.text("2. REGISTRO BIOMÉTRICO DE SEGURIDAD", 20, y);
      y += 10;
      if (formData.selfie) doc.addImage(formData.selfie, 'JPEG', 25, y, 45, 45);
      if (formData.documentFront) doc.addImage(formData.documentFront, 'JPEG', 75, y, 55, 35);

      doc.addPage();
      y = applyLegalTemplate(doc, "Registro de Ingreso Club", 2);
      doc.setFont("helvetica", "bold");
      doc.text("3. CONSENTIMIENTO Y EXONERACIÓN", 20, y);
      y += 10;
      doc.setFontSize(8);
      doc.setFont("helvetica", "normal");
      doc.text("El invitado acepta las normas de convivencia del club y autoriza el registro fotográfico.", 20, y);
      y += 15;
      doc.addImage(signature, 'PNG', 25, y, 60, 25);
      doc.line(25, y + 26, 85, y + 26);
      doc.text("FIRMA DEL INVITADO", 25, y + 32);

      const pdfBase64 = doc.output('datauristring');
      setProcessingStep("SINCRONIZANDO REGISTRO...");

      if (typeof emailjs !== 'undefined') {
        try {
          await emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
            to_email: APP_CONFIG.RECIPIENT_EMAIL,
            subject: `NUEVO INGRESO VIP: ${formData.fullName}`,
            full_name: formData.fullName,
            artistic_name: formData.artisticName,
            message: `Acceso concedido a las ${getFullTimestamp()}.\nDocumento: ${formData.documentNumber}`,
            pdf_attachment: pdfBase64 // Si la plantilla EmailJS tiene adjuntos habilitados
          });
        } catch (e) {
          console.error("Error enviando email de ingreso:", e);
        }
      }

      const startTime = Date.now();
      localStorage.setItem('st_club_session', JSON.stringify({
        start: startTime,
        formData: formData
      }));

      setSessionStartTime(startTime);
      doc.save(`INGRESO_${formData.fullName.replace(/\s/g, '_')}.pdf`);
      setIsProcessing(false);
    } catch (error) {
      console.error(error);
      alert("Error en el protocolo. Por favor intente nuevamente.");
      setIsProcessing(false);
    }
  };

  // --- Cierre de Sesión (Salida de Discoteca) ---
  const handleFinishSession = async () => {
    const durationStr = formatDuration(elapsedTime);
    if (!confirm(`¿Desea cerrar su cuenta y registrar su salida?\nTiempo total: ${durationStr}`)) return;

    setIsProcessing(true);
    setProcessingStep("FINALIZANDO CUENTA VIP...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Reporte de Salida VIP", 1);

      doc.setFontSize(11);
      doc.setTextColor(0, 0, 0);
      doc.text("REPORTE DE PERMANENCIA Y CONSUMO", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 15;

      const report = [
        ["INVITADO:", formData.fullName],
        ["NOMBRE ARTÍSTICO:", formData.artisticName || "N/A"],
        ["DOCUMENTO:", formData.documentNumber],
        ["HORA ENTRADA:", new Date(sessionStartTime!).toLocaleString()],
        ["HORA SALIDA:", getFullTimestamp()],
        ["PERMANENCIA:", durationStr]
      ];

      report.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold");
        doc.text(label, 25, y);
        doc.setFont("helvetica", "normal");
        doc.text(value, 80, y);
        y += 10;
      });

      y += 10;
      doc.setFillColor(245, 245, 250);
      doc.rect(20, y, 170, 25, 'F');
      doc.setFont("helvetica", "bold");
      doc.text("EL INVITADO SE RETIRA SIN NOVEDADES REPORTADAS", 105, y + 15, { align: 'center' });

      const pdfBase64 = doc.output('datauristring');
      setProcessingStep("NOTIFICANDO A ADMINISTRACIÓN...");

      if (typeof emailjs !== 'undefined') {
        try {
          // Intentamos enviar el reporte de salida al email configurado
          await emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
            to_email: APP_CONFIG.RECIPIENT_EMAIL,
            subject: `REPORTE DE SALIDA: ${formData.fullName}`,
            full_name: formData.fullName,
            message: `El invitado ha finalizado su estancia.\nTiempo total: ${durationStr}\nHora de salida: ${getFullTimestamp()}`,
            pdf_attachment: pdfBase64
          });
          console.log("Email de salida enviado con éxito.");
        } catch (e) {
          console.error("Error enviando reporte de salida:", e);
        }
      }

      // Descargar el PDF para el usuario como comprobante
      doc.save(`SALIDA_${formData.fullName.replace(/\s/g, '_')}.pdf`);

      // LIMPIEZA DE SESIÓN
      localStorage.removeItem('st_club_session');
      setIsProcessing(false);
      setShowFinished(true);
    } catch (e) {
      console.error("Error en el proceso de salida:", e);
      alert("Hubo un error al generar el reporte, pero su sesión ha sido cerrada localmente.");
      localStorage.removeItem('st_club_session');
      setShowFinished(true);
    }
  };

  useEffect(() => {
    const saved = localStorage.getItem('st_club_session');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setSessionStartTime(data.start);
        setFormData(data.formData);
        setTermsAccepted(true);
      } catch (e) { 
        localStorage.removeItem('st_club_session'); 
      }
    }
    // Inicializar EmailJS
    if (typeof emailjs !== 'undefined') {
      emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY);
    }
  }, []);

  useEffect(() => {
    let t: number;
    if (sessionStartTime) {
      t = window.setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - sessionStartTime) / 1000));
      }, 1000);
    }
    return () => clearInterval(t);
  }, [sessionStartTime]);

  if (showFinished) return (
    <div className="min-h-screen flex items-center justify-center bg-[#050505] p-6 font-orbitron">
      <div className="max-w-md w-full bg-zinc-900 border border-violet-500/30 p-12 rounded-[3rem] text-center shadow-2xl relative overflow-hidden">
        <div className="absolute -top-24 -right-24 w-48 h-48 bg-violet-600/10 rounded-full blur-3xl"></div>
        <div className="w-24 h-24 bg-violet-500/10 text-violet-500 rounded-full flex items-center justify-center mx-auto mb-10 text-5xl border border-violet-500/20 shadow-[0_0_30px_rgba(139,92,246,0.2)]">✓</div>
        <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter neon-text">CUENTA CERRADA</h2>
        <p className="text-zinc-500 text-[10px] mb-12 tracking-[0.3em] uppercase leading-relaxed font-bold">Registro de salida completado con éxito.</p>
        <button onClick={() => window.location.reload()} className="w-full py-6 bg-white text-black font-black rounded-2xl uppercase text-[11px] tracking-[0.3em] hover:bg-violet-600 hover:text-white transition-all transform hover:scale-105 active:scale-95 shadow-xl">Cerrar Protocolo</button>
      </div>
    </div>
  );

  if (sessionStartTime) return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      <div className="min-h-screen flex flex-col items-center justify-center p-6 text-center">
        <div className="max-w-2xl w-full bg-zinc-950/70 border border-violet-500/20 p-12 rounded-[4.5rem] backdrop-blur-3xl shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-violet-500 to-transparent opacity-50"></div>

          <div className="mb-10">
            <h2 className="text-4xl font-black font-orbitron text-white mb-3 tracking-tighter neon-text">SESIÓN ACTIVA</h2>
            <p className="text-[11px] text-violet-400 font-black tracking-[0.5em] uppercase">{formData.fullName}</p>
          </div>

          <div className="py-24 bg-black/50 border border-zinc-900 rounded-[3.5rem] shadow-inner mb-14 relative group">
            <div className="absolute inset-0 bg-violet-600/5 opacity-0 group-hover:opacity-100 transition-opacity rounded-[3.5rem]"></div>
            <span className="text-7xl sm:text-9xl font-black font-orbitron text-white tracking-widest tabular-nums drop-shadow-[0_0_20px_rgba(139,92,246,0.4)]">
              {new Date(elapsedTime * 1000).toISOString().substr(11, 8)}
            </span>
            <p className="text-[9px] text-zinc-600 mt-6 tracking-[0.4em] font-bold">TIEMPO DE PERMANENCIA</p>
          </div>

          <button 
            onClick={handleFinishSession}
            className="w-full py-8 bg-red-600/10 border border-red-500/30 text-red-500 font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.4em] text-[12px] hover:bg-red-600 hover:text-white transition-all shadow-2xl active:scale-95 group relative overflow-hidden"
          >
            <span className="relative z-10">Reportar Salida y Cerrar Cuenta</span>
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-700"></div>
          </button>
        </div>
      </div>
    </>
  );

  return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      {!termsAccepted ? <TermsModal onAccept={() => setTermsAccepted(true)} /> : (
        <div className="min-h-screen flex items-center justify-center p-4 sm:p-10">
          <div className="max-w-4xl w-full bg-zinc-950/80 border border-zinc-900 p-8 sm:p-20 rounded-[5rem] shadow-2xl relative">
            <header className="text-center mb-16">
              <h1 className="text-5xl sm:text-7xl font-black font-orbitron text-white uppercase tracking-tighter neon-text">{APP_CONFIG.CLUB_NAME}</h1>
              <div className="h-1 w-20 bg-violet-600 mx-auto mt-6 rounded-full"></div>
              <p className="text-[10px] text-zinc-500 font-bold tracking-[0.8em] uppercase mt-6">Protocolo de Acceso VIP</p>
            </header>

            <form onSubmit={handleStartSession} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Completo</label>
                  <input 
                    type="text" 
                    value={formData.fullName} 
                    onChange={e => setFormData({...formData, fullName: e.target.value.toUpperCase()})} 
                    className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all placeholder-zinc-700" 
                    placeholder="INGRESAR NOMBRE"
                    required 
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Artístico</label>
                  <input 
                    type="text" 
                    value={formData.artisticName} 
                    onChange={e => setFormData({...formData, artisticName: e.target.value.toUpperCase()})} 
                    className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all placeholder-zinc-700" 
                    placeholder="ALIAS O SEUDÓNIMO"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Tipo de Documento</label>
                  <select value={formData.documentType} onChange={e => setFormData({...formData, documentType: e.target.value as DocumentType})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all">
                    {Object.values(DocumentType).map(t => <option key={t} value={t} className="bg-zinc-900">{t}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Número Documento</label>
                  <input 
                    type="text" 
                    value={formData.documentNumber} 
                    onChange={e => setFormData({...formData, documentNumber: e.target.value.toUpperCase()})} 
                    className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all placeholder-zinc-700" 
                    placeholder="IDENTIFICACIÓN"
                    required 
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-8">
                {[
                  { k: 'selfie', l: 'Escaneo Facial' },
                  { k: 'documentFront', l: 'ID Frontal' },
                  { k: 'documentBack', l: 'ID Reverso' }
                ].map(item => (
                  <button key={item.k} type="button" onClick={() => { setCameraFor(item.k as any); setIsCameraModalOpen(true); }} className={`p-10 border-2 rounded-[2.5rem] transition-all flex flex-col items-center group relative overflow-hidden ${formData[item.k as keyof FormState] ? 'bg-violet-900/10 border-violet-600 shadow-[0_0_20px_rgba(139,92,246,0.2)]' : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                    <span className="text-[8px] font-black uppercase text-zinc-600 mb-4 group-hover:text-violet-400 tracking-widest">{item.l}</span>
                    <div className="text-3xl text-white group-hover:scale-110 transition-transform">{formData[item.k as keyof FormState] ? '✓' : '+'}</div>
                    {formData[item.k as keyof FormState] && <div className="absolute bottom-0 left-0 w-full h-1 bg-violet-600"></div>}
                  </button>
                ))}
              </div>

              <div className="space-y-6">
                <div className="flex justify-between items-end px-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.4em]">Firma Digital Obligatoria</label>
                  {isSigned && <button type="button" onClick={() => { signaturePadRef.current?.clear(); setIsSigned(false); }} className="text-[9px] font-bold text-red-500 uppercase tracking-widest hover:text-red-400 transition-colors">[ BORRAR ]</button>}
                </div>
                <div className="h-60 bg-black/60 border border-zinc-800 rounded-[3rem] relative overflow-hidden group focus-within:border-violet-600 transition-all shadow-inner">
                  <SignaturePad ref={signaturePadRef} onDrawStart={() => setIsSigned(true)} />
                  {!isSigned && <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-[10px] text-zinc-800 font-black uppercase tracking-[1.5em] opacity-40">Firmar Aquí</div>}
                </div>
              </div>

              <button 
                type="submit" 
                className="w-full py-8 bg-white text-black font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.5em] text-[12px] hover:bg-violet-600 hover:text-white transition-all shadow-2xl active:scale-[0.98] group relative overflow-hidden"
              >
                <span className="relative z-10">Validar Acceso y Activar Sesión</span>
                <div className="absolute inset-0 bg-violet-600 -translate-x-full group-hover:translate-x-0 transition-transform duration-500"></div>
              </button>
            </form>
          </div>
        </div>
      )}
      <CameraModal isOpen={isCameraModalOpen} onClose={() => setIsCameraModalOpen(false)} onCapture={async f => { 
        const b64 = await fileToBase64(f);
        setFormData(p => ({...p, [cameraFor!]: b64})); 
        setIsCameraModalOpen(false); 
      }} purpose={cameraFor} />
    </>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { DocumentType } from './types';
import SignaturePad, { SignaturePadRef } from './components/SignaturePad';
import CameraModal from './components/CameraModal';
import ParticleBackground from './components/ParticleBackground';
import TermsModal from './components/TermsModal';
import ProcessingOverlay from './components/ProcessingOverlay';
import { jsPDF } from 'jspdf';

// === CONFIGURACIÓN DEL CLUB ===
const APP_CONFIG = {
  CLUB_NAME: "SPACE TOWN CLUB",
  RECIPIENT_EMAIL: "appspacetown@gmail.com", 
  EMAILJS: {
    SERVICE_ID: "service_n97bgi4",     
    PUBLIC_KEY: "HHnp6ci-SEnxKhFPA", 
    TEMPLATE_ID: "template_tod2pkl",
  }
};

const LOGO_PNG = "data:image/png;base64,";

declare var emailjs: any;

interface FormState {
  fullName: string;
  documentType: DocumentType | '';
  documentNumber: string;
  artisticName: string;
  selfie?: string; 
  documentFront?: string;
  documentBack?: string;
}

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormState>({
    fullName: '', documentType: DocumentType.CedulaDeCiudadania, documentNumber: '', artisticName: '',
  });
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [sessionStartTime, setSessionStartTime] = useState<number | null>(null);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [showFinished, setShowFinished] = useState(false);

  const signaturePadRef = useRef<SignaturePadRef>(null);

  // --- Helpers ---
  const formatDuration = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h}h ${m}m ${s}s`;
  };

  const getFullTimestamp = () => new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => resolve(e.target?.result as string);
      reader.readAsDataURL(file);
    });
  };

  const uploadPdfAndGetLink = async (pdfBlob: Blob): Promise<string> => {
    try {
      const formDataUpload = new FormData();
      formDataUpload.append('file', pdfBlob, 'documento_spacetown.pdf');
      const response = await fetch('https://tmpfiles.org/api/v1/upload', {
        method: 'POST',
        body: formDataUpload
      });
      const result = await response.json();
      if (result.status === 'success') {
        // Retornamos el link de descarga directa
        return result.data.url.replace('tmpfiles.org/', 'tmpfiles.org/dl/');
      }
      return "N/A (Error de subida)";
    } catch (e) {
      console.error("Error subiendo PDF:", e);
      return "N/A (Fallo de red)";
    }
  };

  const applyLegalTemplate = (doc: jsPDF, title: string, page: number) => {
    const w = doc.internal.pageSize.getWidth();
    const h = doc.internal.pageSize.getHeight();
    const margin = 20;
    doc.setDrawColor(139, 92, 246);
    doc.setLineWidth(0.5);
    doc.line(margin - 2, margin, margin - 2, h - margin); 
    doc.setFillColor(250, 250, 255);
    doc.rect(margin, margin, w - (margin * 2), 30, 'F');
    try { doc.addImage(LOGO_PNG, 'PNG', margin + 5, margin + 5, 20, 20); } catch(e) {}
    doc.setTextColor(20, 20, 30);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.text(APP_CONFIG.CLUB_NAME, margin + 30, margin + 15);
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.text("CONTROL DE ACCESO VIP Y SEGURIDAD PERIMETRAL", margin + 30, margin + 22);
    doc.setTextColor(139, 92, 246);
    doc.setFontSize(10);
    doc.text(title.toUpperCase(), w - margin - 5, margin + 17, { align: 'right' });
    doc.setFontSize(7);
    doc.setTextColor(150, 150, 150);
    doc.text(`REGISTRO OFICIAL - PÁGINA ${page} - CALI, COLOMBIA`, w/2, h - 10, { align: 'center' });
    return margin + 45;
  };

  // --- Inicio de Sesión (Ingreso) ---
  const handleStartSession = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !signature) {
      alert("⚠️ Complete todos los campos, selfie y firma.");
      return;
    }

    setIsProcessing(true);
    setProcessingStep("AUTENTICANDO ACCESO VIP...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Registro de Ingreso Club", 1);

      doc.setFontSize(11);
      doc.text("1. DATOS DEL INVITADO", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 12;

      const info = [
        ["Nombre Completo:", formData.fullName],
        ["Nombre Artístico:", formData.artisticName || "N/A"],
        ["Documento:", `${formData.documentType} ${formData.documentNumber}`],
        ["Hora de Entrada:", getFullTimestamp()]
      ];

      info.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold");
        doc.text(label, 25, y);
        doc.setFont("helvetica", "normal");
        doc.text(value, 70, y);
        y += 8;
      });

      y += 10;
      doc.setFont("helvetica", "bold");
      doc.text("2. REGISTRO BIOMÉTRICO", 20, y);
      y += 10;
      doc.addImage(formData.selfie, 'JPEG', 25, y, 45, 45);
      if (formData.documentFront) doc.addImage(formData.documentFront, 'JPEG', 75, y, 55, 35);

      doc.addPage();
      y = applyLegalTemplate(doc, "Registro de Ingreso Club", 2);
      doc.setFont("helvetica", "bold");
      doc.text("3. FIRMA DE RESPONSABILIDAD", 20, y);
      y += 15;
      doc.addImage(signature, 'PNG', 25, y, 60, 25);
      doc.text("FIRMA DEL INVITADO", 25, y + 32);

      const pdfBlob = doc.output('blob');
      setProcessingStep("SUBIENDO REGISTRO A LA NUBE...");

      const downloadLink = await uploadPdfAndGetLink(pdfBlob);

      setProcessingStep("NOTIFICANDO A SEGURIDAD...");
      if (typeof emailjs !== 'undefined') {
        await emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `INGRESO: ${formData.fullName}`,
          full_name: formData.fullName,
          artistic_name: formData.artisticName,
          message: `Acceso concedido.\nDocumento: ${formData.documentNumber}\nLink PDF: ${downloadLink}`,
          pdf_link: downloadLink
        });
      }

      // Guardar PDF y Sesión
      doc.save(`INGRESO_${formData.fullName.replace(/\s/g, '_')}.pdf`);
      const startTime = Date.now();
      localStorage.setItem('st_club_session', JSON.stringify({ start: startTime, formData }));
      setSessionStartTime(startTime);

    } catch (error) {
      console.error(error);
      alert("Error en el protocolo. Se intentará iniciar de forma local.");
      const startTime = Date.now();
      setSessionStartTime(startTime);
    } finally {
      setIsProcessing(false);
    }
  };

  // --- Cierre de Sesión (Salida) ---
  const handleFinishSession = async () => {
    const durationStr = formatDuration(elapsedTime);
    if (!confirm(`¿Confirmar cierre de cuenta?\nTiempo: ${durationStr}`)) return;

    setIsProcessing(true);
    setProcessingStep("GENERANDO REPORTE DE SALIDA...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Reporte de Salida VIP", 1);

      doc.setFontSize(11);
      doc.text("REPORTE FINAL DE PERMANENCIA", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 15;

      const report = [
        ["INVITADO:", formData.fullName],
        ["NOMBRE ARTÍSTICO:", formData.artisticName || "N/A"],
        ["DOCUMENTO:", formData.documentNumber],
        ["HORA ENTRADA:", new Date(sessionStartTime!).toLocaleString()],
        ["HORA SALIDA:", getFullTimestamp()],
        ["TIEMPO TOTAL:", durationStr]
      ];

      report.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold");
        doc.text(label, 25, y);
        doc.setFont("helvetica", "normal");
        doc.text(value, 80, y);
        y += 10;
      });

      y += 15;
      doc.setFillColor(240, 240, 245);
      doc.rect(20, y, 170, 20, 'F');
      doc.setFont("helvetica", "bold");
      doc.text("SALIDA REGISTRADA SIN NOVEDADES", 105, y + 12, { align: 'center' });

      const pdfBlob = doc.output('blob');
      setProcessingStep("SUBIENDO REPORTE...");

      const downloadLink = await uploadPdfAndGetLink(pdfBlob);

      setProcessingStep("ENVIANDO A ADMINISTRACIÓN...");
      if (typeof emailjs !== 'undefined') {
        await emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `SALIDA: ${formData.fullName}`,
          full_name: formData.fullName,
          message: `Permanencia: ${durationStr}\nHora salida: ${getFullTimestamp()}\nReporte: ${downloadLink}`,
          pdf_link: downloadLink
        });
      }

      doc.save(`SALIDA_${formData.fullName.replace(/\s/g, '_')}.pdf`);

    } catch (e) {
      console.error("Error en salida:", e);
      alert("Error al enviar el reporte, pero su sesión se cerrará.");
    } finally {
      localStorage.removeItem('st_club_session');
      setIsProcessing(false);
      setShowFinished(true);
    }
  };

  useEffect(() => {
    const saved = localStorage.getItem('st_club_session');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setSessionStartTime(data.start);
        setFormData(data.formData);
        setTermsAccepted(true);
      } catch (e) { localStorage.removeItem('st_club_session'); }
    }
    if (typeof emailjs !== 'undefined') emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY);
  }, []);

  useEffect(() => {
    let t: number;
    if (sessionStartTime) {
      t = window.setInterval(() => setElapsedTime(Math.floor((Date.now() - sessionStartTime) / 1000)), 1000);
    }
    return () => clearInterval(t);
  }, [sessionStartTime]);

  if (showFinished) return (
    <div className="min-h-screen flex items-center justify-center bg-[#050505] p-6 font-orbitron">
      <div className="max-w-md w-full bg-zinc-900 border border-violet-500/30 p-12 rounded-[3rem] text-center shadow-2xl relative overflow-hidden">
        <div className="w-24 h-24 bg-violet-500/10 text-violet-500 rounded-full flex items-center justify-center mx-auto mb-10 text-5xl border border-violet-500/20 shadow-[0_0_30px_rgba(139,92,246,0.2)]">✓</div>
        <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter neon-text">CUENTA CERRADA</h2>
        <p className="text-zinc-500 text-[10px] mb-12 tracking-[0.3em] uppercase leading-relaxed font-bold">Protocolo de salida completado.</p>
        <button onClick={() => window.location.reload()} className="w-full py-6 bg-white text-black font-black rounded-2xl uppercase text-[11px] tracking-[0.3em] hover:bg-violet-600 hover:text-white transition-all transform hover:scale-105 active:scale-95 shadow-xl">Cerrar</button>
      </div>
    </div>
  );

  if (sessionStartTime) return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      <div className="min-h-screen flex flex-col items-center justify-center p-6 text-center">
        <div className="max-w-2xl w-full bg-zinc-950/70 border border-violet-500/20 p-12 rounded-[4.5rem] backdrop-blur-3xl shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-violet-500 to-transparent opacity-50"></div>
          <div className="mb-10 text-center">
            <h2 className="text-4xl font-black font-orbitron text-white mb-3 tracking-tighter neon-text">ESTANCIA ACTIVA</h2>
            <p className="text-[11px] text-violet-400 font-black tracking-[0.5em] uppercase">{formData.fullName}</p>
          </div>
          <div className="py-24 bg-black/50 border border-zinc-900 rounded-[3.5rem] shadow-inner mb-14 relative group">
            <span className="text-7xl sm:text-9xl font-black font-orbitron text-white tracking-widest tabular-nums drop-shadow-[0_0_20px_rgba(139,92,246,0.4)]">
              {new Date(elapsedTime * 1000).toISOString().substr(11, 8)}
            </span>
            <p className="text-[9px] text-zinc-600 mt-6 tracking-[0.4em] font-bold uppercase">Tiempo de Permanencia</p>
          </div>
          <button onClick={handleFinishSession} className="w-full py-8 bg-red-600/10 border border-red-500/30 text-red-500 font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.4em] text-[12px] hover:bg-red-600 hover:text-white transition-all shadow-2xl active:scale-95">
            Reportar Salida y Cerrar Cuenta
          </button>
        </div>
      </div>
    </>
  );

  return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      {!termsAccepted ? <TermsModal onAccept={() => setTermsAccepted(true)} /> : (
        <div className="min-h-screen flex items-center justify-center p-4 sm:p-10">
          <div className="max-w-4xl w-full bg-zinc-950/80 border border-zinc-900 p-8 sm:p-20 rounded-[5rem] shadow-2xl relative">
            <header className="text-center mb-16">
              <h1 className="text-5xl sm:text-7xl font-black font-orbitron text-white uppercase tracking-tighter neon-text">{APP_CONFIG.CLUB_NAME}</h1>
              <p className="text-[10px] text-zinc-500 font-bold tracking-[0.8em] uppercase mt-6">Protocolo de Acceso VIP</p>
            </header>
            <form onSubmit={handleStartSession} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Completo</label>
                  <input type="text" value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="INGRESAR NOMBRE" required />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Artístico</label>
                  <input type="text" value={formData.artisticName} onChange={e => setFormData({...formData, artisticName: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="ALIAS O SEUDÓNIMO" />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Tipo de Documento</label>
                  <select value={formData.documentType} onChange={e => setFormData({...formData, documentType: e.target.value as DocumentType})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all">
                    {Object.values(DocumentType).map(t => <option key={t} value={t} className="bg-zinc-900">{t}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Número Documento</label>
                  <input type="text" value={formData.documentNumber} onChange={e => setFormData({...formData, documentNumber: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="IDENTIFICACIÓN" required />
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-8">
                {[{ k: 'selfie', l: 'Escaneo Facial' }, { k: 'documentFront', l: 'ID Frontal' }, { k: 'documentBack', l: 'ID Reverso' }].map(item => (
                  <button key={item.k} type="button" onClick={() => { setCameraFor(item.k as any); setIsCameraModalOpen(true); }} className={`p-10 border-2 rounded-[2.5rem] transition-all flex flex-col items-center group relative overflow-hidden ${formData[item.k as keyof FormState] ? 'bg-violet-900/10 border-violet-600 shadow-[0_0_20px_rgba(139,92,246,0.2)]' : 'bg-zinc-900/30 border-zinc-800'}`}>
                    <span className="text-[8px] font-black uppercase text-zinc-600 mb-4 tracking-widest">{item.l}</span>
                    <div className="text-3xl text-white">{formData[item.k as keyof FormState] ? '✓' : '+'}</div>
                    {formData[item.k as keyof FormState] && <div className="absolute bottom-0 left-0 w-full h-1 bg-violet-600"></div>}
                  </button>
                ))}
              </div>
              <div className="space-y-6">
                <div className="flex justify-between items-end px-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.4em]">Firma Digital Obligatoria</label>
                  {isSigned && <button type="button" onClick={() => { signaturePadRef.current?.clear(); setIsSigned(false); }} className="text-[9px] font-bold text-red-500 uppercase tracking-widest hover:text-red-400">[ BORRAR ]</button>}
                </div>
                <div className="h-60 bg-black/60 border border-zinc-800 rounded-[3rem] relative overflow-hidden group focus-within:border-violet-600 transition-all shadow-inner">
                  <SignaturePad ref={signaturePadRef} onDrawStart={() => setIsSigned(true)} />
                  {!isSigned && <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-[10px] text-zinc-800 font-black uppercase tracking-[1.5em] opacity-40">Firmar Aquí</div>}
                </div>
              </div>
              <button type="submit" className="w-full py-8 bg-white text-black font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.5em] text-[12px] hover:bg-violet-600 hover:text-white transition-all shadow-2xl active:scale-[0.98]">
                Validar Acceso y Activar Sesión
              </button>
            </form>
          </div>
        </div>
      )}
      <CameraModal isOpen={isCameraModalOpen} onClose={() => setIsCameraModalOpen(false)} onCapture={async f => { 
        const b64 = await fileToBase64(f);
        setFormData(p => ({...p, [cameraFor!]: b64})); 
        setIsCameraModalOpen(false); 
      }} purpose={cameraFor} />
    </>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { DocumentType } from './types';
import SignaturePad, { SignaturePadRef } from './components/SignaturePad';
import CameraModal from './components/CameraModal';
import ParticleBackground from './components/ParticleBackground';
import TermsModal from './components/TermsModal';
import ProcessingOverlay from './components/ProcessingOverlay';
import { jsPDF } from 'jspdf';

// === CONFIGURACIÓN DEL CLUB ===
const APP_CONFIG = {
  CLUB_NAME: "SPACE TOWN CLUB",
  RECIPIENT_EMAIL: "appspacetown@gmail.com", 
  EMAILJS: {
    SERVICE_ID: "service_n97bgi4",     
    PUBLIC_KEY: "HHnp6ci-SEnxKhFPA", 
    TEMPLATE_ID: "template_tod2pkl",
  }
};

const LOGO_PNG = "data:image/png;base64,";

// Declaración global para EmailJS
declare global {
  interface Window {
    emailjs: any;
  }
}

interface FormState {
  fullName: string;
  documentType: DocumentType | '';
  documentNumber: string;
  artisticName: string;
  selfie?: string; 
  documentFront?: string;
  documentBack?: string;
}

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormState>({
    fullName: '', documentType: DocumentType.CedulaDeCiudadania, documentNumber: '', artisticName: '',
  });
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [sessionStartTime, setSessionStartTime] = useState<number | null>(null);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [showFinished, setShowFinished] = useState(false);

  const signaturePadRef = useRef<SignaturePadRef>(null);

  // --- Helpers ---
  const formatDuration = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h}h ${m}m ${s}s`;
  };

  const getFullTimestamp = () => new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => resolve(e.target?.result as string);
      reader.readAsDataURL(file);
    });
  };

  const uploadPdfAndGetLink = async (pdfBlob: Blob): Promise<string> => {
    try {
      const formDataUpload = new FormData();
      formDataUpload.append('file', pdfBlob, 'spacetown_report.pdf');
      const response = await fetch('https://tmpfiles.org/api/v1/upload', {
        method: 'POST',
        body: formDataUpload
      });
      const result = await response.json();
      if (result.status === 'success') {
        return result.data.url.replace('tmpfiles.org/', 'tmpfiles.org/dl/');
      }
      return "No se pudo generar enlace";
    } catch (e) {
      console.error("Error en upload:", e);
      return "Fallo de conexión";
    }
  };

  const applyLegalTemplate = (doc: jsPDF, title: string, page: number) => {
    const w = doc.internal.pageSize.getWidth();
    const h = doc.internal.pageSize.getHeight();
    const margin = 20;
    doc.setDrawColor(139, 92, 246);
    doc.setLineWidth(0.5);
    doc.line(margin - 2, margin, margin - 2, h - margin); 
    doc.setFillColor(250, 250, 255);
    doc.rect(margin, margin, w - (margin * 2), 30, 'F');
    try { doc.addImage(LOGO_PNG, 'PNG', margin + 5, margin + 5, 20, 20); } catch(e) {}
    doc.setTextColor(20, 20, 30);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.text(APP_CONFIG.CLUB_NAME, margin + 30, margin + 15);
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.text("CONTROL DE ACCESO VIP Y SEGURIDAD PERIMETRAL", margin + 30, margin + 22);
    doc.setTextColor(139, 92, 246);
    doc.setFontSize(10);
    doc.text(title.toUpperCase(), w - margin - 5, margin + 17, { align: 'right' });
    doc.setFontSize(7);
    doc.setTextColor(150, 150, 150);
    doc.text(`REGISTRO OFICIAL - PÁGINA ${page} - CALI, COLOMBIA`, w/2, h - 10, { align: 'center' });
    return margin + 45;
  };

  // --- Inicio de Sesión (Ingreso) ---
  const handleStartSession = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !signature) {
      alert("⚠️ Por favor complete todos los datos, incluyendo la selfie y la firma.");
      return;
    }

    setIsProcessing(true);
    setProcessingStep("GENERANDO REGISTRO DE INGRESO...");

    let doc: jsPDF | null = null;
    try {
      doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Registro de Ingreso Club", 1);

      doc.setFontSize(11);
      doc.text("1. DATOS DEL INVITADO", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 12;

      const info = [
        ["Nombre Completo:", formData.fullName],
        ["Nombre Artístico:", formData.artisticName || "N/A"],
        ["Documento:", `${formData.documentType} ${formData.documentNumber}`],
        ["Hora de Entrada:", getFullTimestamp()]
      ];

      info.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold");
        doc.text(label, 25, y);
        doc.setFont("helvetica", "normal");
        doc.text(value, 70, y);
        y += 8;
      });

      y += 10;
      doc.setFont("helvetica", "bold");
      doc.text("2. REGISTRO BIOMÉTRICO", 20, y);
      y += 10;
      doc.addImage(formData.selfie, 'JPEG', 25, y, 45, 45);
      if (formData.documentFront) doc.addImage(formData.documentFront, 'JPEG', 75, y, 55, 35);

      doc.addPage();
      y = applyLegalTemplate(doc, "Registro de Ingreso Club", 2);
      doc.setFont("helvetica", "bold");
      doc.text("3. FIRMA DE RESPONSABILIDAD", 20, y);
      y += 15;
      doc.addImage(signature, 'PNG', 25, y, 60, 25);
      doc.text("FIRMA DEL INVITADO", 25, y + 32);

      const pdfBlob = doc.output('blob');
      setProcessingStep("SINCRONIZANDO CON SEGURIDAD...");

      const downloadLink = await uploadPdfAndGetLink(pdfBlob);

      if (window.emailjs) {
        await window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `INGRESO VIP: ${formData.fullName}`,
          full_name: formData.fullName,
          artistic_name: formData.artisticName,
          message: `Nuevo ingreso registrado.\nDocumento: ${formData.documentNumber}\nReporte: ${downloadLink}`,
          pdf_link: downloadLink
        });
      }

      // Descarga obligatoria
      doc.save(`INGRESO_${formData.fullName.replace(/\s/g, '_')}.pdf`);

      const startTime = Date.now();
      localStorage.setItem('st_club_session', JSON.stringify({ start: startTime, formData }));
      setSessionStartTime(startTime);
      setTermsAccepted(true);

    } catch (error) {
      console.error("Error en ingreso:", error);
      alert("Error en el protocolo. Se procederá con el registro local.");
      const startTime = Date.now();
      setSessionStartTime(startTime);
    } finally {
      setIsProcessing(false);
    }
  };

  // --- Cierre de Sesión (Salida) ---
  const handleFinishSession = async () => {
    const durationStr = formatDuration(elapsedTime);
    if (!confirm(`¿Confirmar cierre de cuenta y reporte de salida?\nTiempo total: ${durationStr}`)) return;

    setIsProcessing(true);
    setProcessingStep("GENERANDO REPORTE DE SALIDA...");

    let doc: jsPDF | null = null;
    try {
      doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Certificado de Salida VIP", 1);

      doc.setFontSize(11);
      doc.text("REPORTE DE PERMANENCIA", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 15;

      const report = [
        ["INVITADO:", formData.fullName],
        ["ALIAS:", formData.artisticName || "N/A"],
        ["IDENTIFICACIÓN:", formData.documentNumber],
        ["HORA ENTRADA:", new Date(sessionStartTime!).toLocaleString()],
        ["HORA SALIDA:", getFullTimestamp()],
        ["DURACIÓN:", durationStr]
      ];

      report.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold");
        doc.text(label, 25, y);
        doc.setFont("helvetica", "normal");
        doc.text(value, 80, y);
        y += 10;
      });

      y += 15;
      doc.setFillColor(245, 245, 250);
      doc.rect(20, y, 170, 20, 'F');
      doc.setFont("helvetica", "bold");
      doc.text("SALIDA EXITOSA - SIN NOVEDADES REPORTADAS", 105, y + 12, { align: 'center' });

      const pdfBlob = doc.output('blob');
      setProcessingStep("ENVIANDO REPORTE FINAL...");

      const downloadLink = await uploadPdfAndGetLink(pdfBlob);

      if (window.emailjs) {
        await window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `SALIDA CLUB: ${formData.fullName}`,
          full_name: formData.fullName,
          message: `El invitado ha salido del club.\nPermanencia: ${durationStr}\nReporte: ${downloadLink}`,
          pdf_link: downloadLink
        });
      }

      // Descarga obligatoria
      doc.save(`SALIDA_${formData.fullName.replace(/\s/g, '_')}.pdf`);

    } catch (e) {
      console.error("Error en reporte de salida:", e);
    } finally {
      // Limpieza siempre, ocurra o no un error arriba
      localStorage.removeItem('st_club_session');
      setIsProcessing(false);
      setShowFinished(true);
    }
  };

  useEffect(() => {
    const saved = localStorage.getItem('st_club_session');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setSessionStartTime(data.start);
        setFormData(data.formData);
        setTermsAccepted(true);
      } catch (e) { 
        localStorage.removeItem('st_club_session'); 
      }
    }

    // Inicializar EmailJS con la clave pública
    if (window.emailjs) {
      window.emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY);
    }
  }, []);

  useEffect(() => {
    let t: number;
    if (sessionStartTime) {
      t = window.setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - sessionStartTime) / 1000));
      }, 1000);
    }
    return () => clearInterval(t);
  }, [sessionStartTime]);

  if (showFinished) return (
    <div className="min-h-screen flex items-center justify-center bg-[#050505] p-6 font-orbitron">
      <div className="max-w-md w-full bg-zinc-900 border border-violet-500/30 p-12 rounded-[3rem] text-center shadow-2xl relative overflow-hidden">
        <div className="w-24 h-24 bg-violet-500/10 text-violet-500 rounded-full flex items-center justify-center mx-auto mb-10 text-5xl border border-violet-500/20 shadow-[0_0_30px_rgba(139,92,246,0.2)]">✓</div>
        <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter neon-text">CUENTA CERRADA</h2>
        <p className="text-zinc-500 text-[10px] mb-12 tracking-[0.3em] uppercase leading-relaxed font-bold">Reporte de salida procesado correctamente.</p>
        <button onClick={() => window.location.reload()} className="w-full py-6 bg-white text-black font-black rounded-2xl uppercase text-[11px] tracking-[0.3em] hover:bg-violet-600 hover:text-white transition-all transform hover:scale-105 active:scale-95 shadow-xl">Cerrar Sistema</button>
      </div>
    </div>
  );

  if (sessionStartTime) return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      <div className="min-h-screen flex flex-col items-center justify-center p-6 text-center">
        <div className="max-w-2xl w-full bg-zinc-950/70 border border-violet-500/20 p-12 rounded-[4.5rem] backdrop-blur-3xl shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-violet-500 to-transparent opacity-50"></div>
          <div className="mb-10">
            <h2 className="text-4xl font-black font-orbitron text-white mb-3 tracking-tighter neon-text">ESTANCIA ACTIVA</h2>
            <p className="text-[11px] text-violet-400 font-black tracking-[0.5em] uppercase">{formData.fullName}</p>
          </div>
          <div className="py-24 bg-black/50 border border-zinc-900 rounded-[3.5rem] shadow-inner mb-14 relative">
            <span className="text-7xl sm:text-9xl font-black font-orbitron text-white tracking-widest tabular-nums drop-shadow-[0_0_20px_rgba(139,92,246,0.4)]">
              {new Date(elapsedTime * 1000).toISOString().substr(11, 8)}
            </span>
            <p className="text-[9px] text-zinc-600 mt-6 tracking-[0.4em] font-bold uppercase">Tiempo Transcurrido</p>
          </div>
          <button 
            onClick={handleFinishSession} 
            className="w-full py-8 bg-red-600/10 border border-red-500/30 text-red-500 font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.4em] text-[12px] hover:bg-red-600 hover:text-white transition-all shadow-2xl active:scale-95"
          >
            Reportar Salida y Cerrar Cuenta
          </button>
        </div>
      </div>
    </>
  );

  return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      {!termsAccepted ? <TermsModal onAccept={() => setTermsAccepted(true)} /> : (
        <div className="min-h-screen flex items-center justify-center p-4 sm:p-10">
          <div className="max-w-4xl w-full bg-zinc-950/80 border border-zinc-900 p-8 sm:p-20 rounded-[5rem] shadow-2xl relative">
            <header className="text-center mb-16">
              <h1 className="text-5xl sm:text-7xl font-black font-orbitron text-white uppercase tracking-tighter neon-text">{APP_CONFIG.CLUB_NAME}</h1>
              <p className="text-[10px] text-zinc-500 font-bold tracking-[0.8em] uppercase mt-6">Protocolo de Acceso VIP</p>
            </header>
            <form onSubmit={handleStartSession} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Completo</label>
                  <input type="text" value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="NOMBRE COMPLETO" required />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Artístico</label>
                  <input type="text" value={formData.artisticName} onChange={e => setFormData({...formData, artisticName: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="SEUDÓNIMO" />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Tipo de Documento</label>
                  <select value={formData.documentType} onChange={e => setFormData({...formData, documentType: e.target.value as DocumentType})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all">
                    {Object.values(DocumentType).map(t => <option key={t} value={t} className="bg-zinc-900">{t}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Número Documento</label>
                  <input type="text" value={formData.documentNumber} onChange={e => setFormData({...formData, documentNumber: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="IDENTIFICACIÓN" required />
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-8">
                {[{ k: 'selfie', l: 'Escaneo Facial' }, { k: 'documentFront', l: 'ID Frontal' }, { k: 'documentBack', l: 'ID Reverso' }].map(item => (
                  <button key={item.k} type="button" onClick={() => { setCameraFor(item.k as any); setIsCameraModalOpen(true); }} className={`p-10 border-2 rounded-[2.5rem] transition-all flex flex-col items-center group relative overflow-hidden ${formData[item.k as keyof FormState] ? 'bg-violet-900/10 border-violet-600 shadow-[0_0_20px_rgba(139,92,246,0.2)]' : 'bg-zinc-900/30 border-zinc-800'}`}>
                    <span className="text-[8px] font-black uppercase text-zinc-600 mb-4 tracking-widest">{item.l}</span>
                    <div className="text-3xl text-white">{formData[item.k as keyof FormState] ? '✓' : '+'}</div>
                    {formData[item.k as keyof FormState] && <div className="absolute bottom-0 left-0 w-full h-1 bg-violet-600"></div>}
                  </button>
                ))}
              </div>
              <div className="space-y-6">
                <div className="flex justify-between items-end px-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.4em]">Firma Digital Obligatoria</label>
                  {isSigned && <button type="button" onClick={() => { signaturePadRef.current?.clear(); setIsSigned(false); }} className="text-[9px] font-bold text-red-500 uppercase tracking-widest hover:text-red-400">[ BORRAR ]</button>}
                </div>
                <div className="h-60 bg-black/60 border border-zinc-800 rounded-[3rem] relative overflow-hidden group focus-within:border-violet-600 transition-all shadow-inner">
                  <SignaturePad ref={signaturePadRef} onDrawStart={() => setIsSigned(true)} />
                  {!isSigned && <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-[10px] text-zinc-800 font-black uppercase tracking-[1.5em] opacity-40">Firmar Aquí</div>}
                </div>
              </div>
              <button type="submit" className="w-full py-8 bg-white text-black font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.5em] text-[12px] hover:bg-violet-600 hover:text-white transition-all shadow-2xl active:scale-[0.98]">
                Validar Acceso y Activar Sesión
              </button>
            </form>
          </div>
        </div>
      )}
      <CameraModal isOpen={isCameraModalOpen} onClose={() => setIsCameraModalOpen(false)} onCapture={async f => { 
        const b64 = await fileToBase64(f);
        setFormData(p => ({...p, [cameraFor!]: b64})); 
        setIsCameraModalOpen(false); 
      }} purpose={cameraFor} />
    </>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { DocumentType } from './types';
import SignaturePad, { SignaturePadRef } from './components/SignaturePad';
import CameraModal from './components/CameraModal';
import ParticleBackground from './components/ParticleBackground';
import TermsModal from './components/TermsModal';
import ProcessingOverlay from './components/ProcessingOverlay';
import { jsPDF } from 'jspdf';

// === CONFIGURACIÓN DEL CLUB ===
const APP_CONFIG = {
  CLUB_NAME: "SPACE TOWN CLUB",
  RECIPIENT_EMAIL: "appspacetown@gmail.com", 
  EMAILJS: {
    SERVICE_ID: "service_n97bgi4",     
    PUBLIC_KEY: "HHnp6ci-SEnxKhFPA", 
    TEMPLATE_ID: "template_tod2pkl",
  }
};

const LOGO_PNG = "data:image/png;base64,";

// Declaración global para EmailJS
declare global {
  interface Window {
    emailjs: any;
  }
}

interface FormState {
  fullName: string;
  documentType: DocumentType | '';
  documentNumber: string;
  artisticName: string;
  selfie?: string; 
  documentFront?: string;
  documentBack?: string;
}

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormState>({
    fullName: '', documentType: DocumentType.CedulaDeCiudadania, documentNumber: '', artisticName: '',
  });
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [sessionStartTime, setSessionStartTime] = useState<number | null>(null);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [showFinished, setShowFinished] = useState(false);

  const signaturePadRef = useRef<SignaturePadRef>(null);

  // --- Helpers ---
  const formatDuration = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h}h ${m}m ${s}s`;
  };

  const getFullTimestamp = () => new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => resolve(e.target?.result as string);
      reader.readAsDataURL(file);
    });
  };

  const uploadPdfWithTimeout = async (pdfBlob: Blob): Promise<string> => {
    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 8000); // 8 segundos de timeout

      const formDataUpload = new FormData();
      formDataUpload.append('file', pdfBlob, 'reporte_spacetown.pdf');

      const response = await fetch('https://tmpfiles.org/api/v1/upload', {
        method: 'POST',
        body: formDataUpload,
        signal: controller.signal
      });
      clearTimeout(timeoutId);

      const result = await response.json();
      if (result.status === 'success') {
        return result.data.url.replace('tmpfiles.org/', 'tmpfiles.org/dl/');
      }
      return "Enlace no disponible (Error API)";
    } catch (e) {
      console.error("Fallo subida PDF:", e);
      return "Fallo conexión servidor";
    }
  };

  const applyLegalTemplate = (doc: jsPDF, title: string, page: number) => {
    const w = doc.internal.pageSize.getWidth();
    const h = doc.internal.pageSize.getHeight();
    const margin = 20;
    doc.setDrawColor(139, 92, 246);
    doc.setLineWidth(0.5);
    doc.line(margin - 2, margin, margin - 2, h - margin); 
    doc.setFillColor(250, 250, 255);
    doc.rect(margin, margin, w - (margin * 2), 30, 'F');
    try { doc.addImage(LOGO_PNG, 'PNG', margin + 5, margin + 5, 20, 20); } catch(e) {}
    doc.setTextColor(20, 20, 30);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.text(APP_CONFIG.CLUB_NAME, margin + 30, margin + 15);
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.text("CONTROL DE ACCESO VIP Y SEGURIDAD PERIMETRAL", margin + 30, margin + 22);
    doc.setTextColor(139, 92, 246);
    doc.setFontSize(10);
    doc.text(title.toUpperCase(), w - margin - 5, margin + 17, { align: 'right' });
    doc.setFontSize(7);
    doc.setTextColor(150, 150, 150);
    doc.text(`REGISTRO OFICIAL - PÁGINA ${page} - CALI, COLOMBIA`, w/2, h - 10, { align: 'center' });
    return margin + 45;
  };

  // --- Inicio de Sesión (Ingreso) ---
  const handleStartSession = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !signature) {
      alert("⚠️ Por favor complete todos los datos, selfie y firma.");
      return;
    }

    setIsProcessing(true);
    setProcessingStep("AUTENTICANDO ACCESO...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Registro de Ingreso Club", 1);

      doc.setFontSize(11);
      doc.text("1. DATOS DEL INVITADO", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 12;

      const info = [
        ["Nombre Completo:", formData.fullName],
        ["Nombre Artístico:", formData.artisticName || "N/A"],
        ["Documento:", `${formData.documentType} ${formData.documentNumber}`],
        ["Hora de Entrada:", getFullTimestamp()]
      ];

      info.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold");
        doc.text(label, 25, y);
        doc.setFont("helvetica", "normal");
        doc.text(value, 70, y);
        y += 8;
      });

      y += 10;
      doc.setFont("helvetica", "bold");
      doc.text("2. BIOMETRÍA", 20, y);
      y += 10;
      doc.addImage(formData.selfie, 'JPEG', 25, y, 45, 45);
      if (formData.documentFront) doc.addImage(formData.documentFront, 'JPEG', 75, y, 55, 35);

      doc.addPage();
      y = applyLegalTemplate(doc, "Registro de Ingreso Club", 2);
      doc.setFont("helvetica", "bold");
      doc.text("3. FIRMA DIGITAL", 20, y);
      y += 15;
      doc.addImage(signature, 'PNG', 25, y, 60, 25);
      doc.text("FIRMA DEL INVITADO", 25, y + 32);

      const pdfBlob = doc.output('blob');
      setProcessingStep("NOTIFICANDO A SEGURIDAD...");

      const link = await uploadPdfWithTimeout(pdfBlob);

      if (window.emailjs) {
        await window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `NUEVO INGRESO: ${formData.fullName}`,
          full_name: formData.fullName,
          message: `Ingreso validado.\nDocumento: ${formData.documentNumber}\nReporte: ${link}`,
          pdf_link: link
        }).catch(err => console.error("EmailJS Error:", err));
      }

      doc.save(`INGRESO_${formData.fullName.replace(/\s/g, '_')}.pdf`);

      const startTime = Date.now();
      localStorage.setItem('st_club_session', JSON.stringify({ start: startTime, formData }));
      setSessionStartTime(startTime);
      setTermsAccepted(true);

    } catch (error) {
      console.error("Error ingreso:", error);
      alert("Error en el protocolo. Se iniciará la sesión localmente.");
      const startTime = Date.now();
      setSessionStartTime(startTime);
    } finally {
      setIsProcessing(false);
    }
  };

  // --- Cierre de Sesión (Salida) ---
  const handleFinishSession = async () => {
    const durationStr = formatDuration(elapsedTime);
    if (!confirm(`¿Confirmar cierre de cuenta?\nTiempo total: ${durationStr}`)) return;

    setIsProcessing(true);
    setProcessingStep("PREPARANDO REPORTE DE SALIDA...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Protocolo de Salida VIP", 1);

      doc.setFontSize(11);
      doc.text("REPORTE FINAL DE PERMANENCIA", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 15;

      const report = [
        ["NOMBRE:", formData.fullName],
        ["ALIAS:", formData.artisticName || "N/A"],
        ["DOCUMENTO:", formData.documentNumber],
        ["ENTRADA:", new Date(sessionStartTime || Date.now()).toLocaleString()],
        ["SALIDA:", getFullTimestamp()],
        ["PERMANENCIA:", durationStr]
      ];

      report.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold");
        doc.text(label, 25, y);
        doc.setFont("helvetica", "normal");
        doc.text(value, 80, y);
        y += 10;
      });

      y += 15;
      doc.setFillColor(245, 245, 250);
      doc.rect(20, y, 170, 20, 'F');
      doc.setFont("helvetica", "bold");
      doc.text("CUENTA CERRADA - SALIDA SIN NOVEDAD", 105, y + 12, { align: 'center' });

      const pdfBlob = doc.output('blob');
      setProcessingStep("ACTUALIZANDO REGISTROS...");

      const link = await uploadPdfWithTimeout(pdfBlob);

      if (window.emailjs) {
        // No bloqueamos la ejecución si EmailJS tarda
        window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `SALIDA REGISTRADA: ${formData.fullName}`,
          full_name: formData.fullName,
          message: `Salida completada.\nDuración estancia: ${durationStr}\nReporte: ${link}`,
          pdf_link: link
        }).catch(err => console.error("EmailJS Error:", err));
      }

      // Descargamos el reporte para el usuario
      doc.save(`REPORTE_SALIDA_${formData.fullName.replace(/\s/g, '_')}.pdf`);

    } catch (e) {
      console.error("Error en reporte:", e);
    } finally {
      // SIEMPRE finalizamos, aunque falle la subida o el email
      localStorage.removeItem('st_club_session');
      setIsProcessing(false);
      setShowFinished(true);
    }
  };

  const resetAll = () => {
    localStorage.removeItem('st_club_session');
    setShowFinished(false);
    setSessionStartTime(null);
    setFormData({
      fullName: '', documentType: DocumentType.CedulaDeCiudadania, documentNumber: '', artisticName: '',
    });
    setTermsAccepted(false);
    setIsSigned(false);
    setElapsedTime(0);
  };

  useEffect(() => {
    const saved = localStorage.getItem('st_club_session');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setSessionStartTime(data.start);
        setFormData(data.formData);
        setTermsAccepted(true);
      } catch (e) { 
        localStorage.removeItem('st_club_session'); 
      }
    }

    if (window.emailjs) {
      window.emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY);
    }
  }, []);

  useEffect(() => {
    let t: number;
    if (sessionStartTime) {
      t = window.setInterval(() => {
        setElapsedTime(Math.floor((Date.now() - sessionStartTime) / 1000));
      }, 1000);
    }
    return () => clearInterval(t);
  }, [sessionStartTime]);

  if (showFinished) return (
    <div className="min-h-screen flex items-center justify-center bg-[#050505] p-6 font-orbitron">
      <div className="max-w-md w-full bg-zinc-900 border border-violet-500/30 p-12 rounded-[3rem] text-center shadow-2xl relative overflow-hidden">
        <div className="w-24 h-24 bg-violet-500/10 text-violet-500 rounded-full flex items-center justify-center mx-auto mb-10 text-5xl border border-violet-500/20 shadow-[0_0_30px_rgba(139,92,246,0.2)]">✓</div>
        <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter neon-text">OPERACIÓN EXITOSA</h2>
        <p className="text-zinc-500 text-[10px] mb-12 tracking-[0.3em] uppercase leading-relaxed font-bold">La sesión ha finalizado y el reporte ha sido generado.</p>
        <button onClick={resetAll} className="w-full py-6 bg-white text-black font-black rounded-2xl uppercase text-[11px] tracking-[0.3em] hover:bg-violet-600 hover:text-white transition-all transform hover:scale-105 active:scale-95 shadow-xl">Nuevo Registro</button>
      </div>
    </div>
  );

  if (sessionStartTime) return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      <div className="min-h-screen flex flex-col items-center justify-center p-6 text-center">
        <div className="max-w-2xl w-full bg-zinc-950/70 border border-violet-500/20 p-12 rounded-[4.5rem] backdrop-blur-3xl shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-violet-500 to-transparent opacity-50"></div>
          <div className="mb-10">
            <h2 className="text-4xl font-black font-orbitron text-white mb-3 tracking-tighter neon-text">VIP ACTIVO</h2>
            <p className="text-[11px] text-violet-400 font-black tracking-[0.5em] uppercase">{formData.fullName}</p>
          </div>
          <div className="py-24 bg-black/50 border border-zinc-900 rounded-[3.5rem] shadow-inner mb-14 relative">
            <span className="text-7xl sm:text-9xl font-black font-orbitron text-white tracking-widest tabular-nums drop-shadow-[0_0_20px_rgba(139,92,246,0.4)]">
              {new Date(elapsedTime * 1000).toISOString().substr(11, 8)}
            </span>
            <p className="text-[9px] text-zinc-600 mt-6 tracking-[0.4em] font-bold uppercase">Tiempo en el Club</p>
          </div>
          <button 
            onClick={handleFinishSession} 
            className="w-full py-8 bg-red-600/10 border border-red-500/30 text-red-500 font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.4em] text-[12px] hover:bg-red-600 hover:text-white transition-all shadow-2xl active:scale-95"
          >
            Reportar Salida y Cerrar Cuenta
          </button>
        </div>
      </div>
    </>
  );

  return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      {!termsAccepted ? <TermsModal onAccept={() => setTermsAccepted(true)} /> : (
        <div className="min-h-screen flex items-center justify-center p-4 sm:p-10">
          <div className="max-w-4xl w-full bg-zinc-950/80 border border-zinc-900 p-8 sm:p-20 rounded-[5rem] shadow-2xl relative">
            <header className="text-center mb-16">
              <h1 className="text-5xl sm:text-7xl font-black font-orbitron text-white uppercase tracking-tighter neon-text">{APP_CONFIG.CLUB_NAME}</h1>
              <p className="text-[10px] text-zinc-500 font-bold tracking-[0.8em] uppercase mt-6">Protocolo de Acceso VIP</p>
            </header>
            <form onSubmit={handleStartSession} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Completo</label>
                  <input type="text" value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="NOMBRE COMPLETO" required />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Artístico</label>
                  <input type="text" value={formData.artisticName} onChange={e => setFormData({...formData, artisticName: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="SEUDÓNIMO" />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Tipo de Documento</label>
                  <select value={formData.documentType} onChange={e => setFormData({...formData, documentType: e.target.value as DocumentType})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all">
                    {Object.values(DocumentType).map(t => <option key={t} value={t} className="bg-zinc-900">{t}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Número Documento</label>
