    doc.text(APP_CONFIG.CLUB_NAME, margin + 30, margin + 15);
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.text("SISTEMA DE SEGURIDAD Y CONTROL VIP", margin + 30, margin + 22);
    doc.setTextColor(139, 92, 246);
    doc.setFontSize(10);
    doc.text(title.toUpperCase(), w - margin - 5, margin + 17, { align: 'right' });
    doc.setFontSize(7);
    doc.setTextColor(150, 150, 150);
    doc.text(`REGISTRO DIGITAL - PÁGINA ${page} - COLOMBIA`, w/2, h - 10, { align: 'center' });
    return margin + 45;
  };

  const handleStartSession = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !signature) {
      alert("⚠️ Por favor complete todos los campos, selfie y firma obligatoria.");
      return;
    }

    setIsProcessing(true);
    setProcessingStep("INICIANDO PROTOCOLO DE ACCESO...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Registro de Ingreso", 1);

      doc.setFontSize(11);
      doc.text("DATOS DEL INVITADO VIP", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 12;

      const info = [
        ["Nombre Completo:", formData.fullName],
        ["Nombre Artístico:", formData.artisticName || "No especificado"],
        ["Tipo Documento:", formData.documentType],
        ["Documento ID:", formData.documentNumber],
        ["Fecha y Hora:", getFullTimestamp()]
      ];

      info.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold"); doc.text(label, 25, y);
        doc.setFont("helvetica", "normal"); doc.text(value, 70, y);
        y += 8;
      });

      y += 10;
      doc.setFont("helvetica", "bold"); doc.text("IDENTIFICACIÓN BIOMÉTRICA", 20, y);
      y += 10;
      doc.addImage(formData.selfie, 'JPEG', 25, y, 45, 45);
      if (formData.documentFront) doc.addImage(formData.documentFront, 'JPEG', 75, y, 55, 35);

      doc.addPage();
      y = applyLegalTemplate(doc, "Registro de Ingreso", 2);
      doc.setFont("helvetica", "bold"); doc.text("VALIDACIÓN DE FIRMA", 20, y);
      y += 15;
      doc.addImage(signature, 'PNG', 25, y, 60, 25);

      const pdfBlob = doc.output('blob');
      setProcessingStep("ENVIANDO REGISTRO A SEGURIDAD...");

      const link = await uploadPdfToCloud(pdfBlob);

      if (window.emailjs) {
        await window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `INGRESO: ${formData.fullName}`,
          message: `Acceso validado para ${formData.fullName} (${formData.artisticName}).\nPDF: ${link}`,
          pdf_link: link
        });
      }

      doc.save(`INGRESO_${formData.fullName.replace(/\s/g, '_')}.pdf`);

      const startTime = Date.now();
      localStorage.setItem('st_club_session', JSON.stringify({ start: startTime, formData }));
      setSessionStartTime(startTime);

    } catch (err) {
      console.error(err);
      setSessionStartTime(Date.now());
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFinishSession = async () => {
    const durationStr = formatDuration(elapsedTime);
    if (!confirm(`¿Confirmar reporte de salida?\nTiempo en el club: ${durationStr}`)) return;

    setIsProcessing(true);
    setProcessingStep("GENERANDO REPORTE DE SALIDA...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Certificado de Salida", 1);

      doc.setFontSize(11);
      doc.text("REPORTE FINAL", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 15;

      const report = [
        ["INVITADO:", formData.fullName],
        ["ALIAS:", formData.artisticName],
        ["DOCUMENTO:", formData.documentNumber],
        ["DURACIÓN ESTANCIA:", durationStr],
        ["HORA DE SALIDA:", getFullTimestamp()]
      ];

      report.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold"); doc.text(label, 25, y);
        doc.setFont("helvetica", "normal"); doc.text(value, 80, y);
        y += 10;
      });

      doc.setFillColor(245, 245, 250);
      doc.rect(20, y + 10, 170, 20, 'F');
      doc.text("SALIDA EXITOSA - CUENTA FINALIZADA", 105, y + 22, { align: 'center' });

      const pdfBlob = doc.output('blob');
      setProcessingStep("SINCRONIZANDO DATOS...");

      const link = await uploadPdfToCloud(pdfBlob);

      if (window.emailjs) {
