          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `SALIDA: ${formData.fullName}`,
          message: `El invitado ha salido. Permanencia: ${durationStr}.\nReporte: ${link}`,
          pdf_link: link
        });
      }

      doc.save(`SALIDA_${formData.fullName.replace(/\s/g, '_')}.pdf`);

    } catch (e) {
      console.error("Error en salida:", e);
    } finally {
      localStorage.removeItem('st_club_session');
      setIsProcessing(false);
      setShowFinished(true);
      setSessionStartTime(null);
    }
  };

  const resetAll = () => {
    localStorage.removeItem('st_club_session');
    setShowFinished(false);
    setFormData({ fullName: '', documentType: DocumentType.CedulaDeCiudadania, documentNumber: '', artisticName: '', });
    setTermsAccepted(false);
    setIsSigned(false);
    setElapsedTime(0);
  };

  useEffect(() => {
    const saved = localStorage.getItem('st_club_session');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        setSessionStartTime(data.start);
        setFormData(data.formData);
        setTermsAccepted(true);
      } catch (e) { localStorage.removeItem('st_club_session'); }
    }
    if (window.emailjs) window.emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY);
  }, []);

  useEffect(() => {
    let t: number;
    if (sessionStartTime) {
      t = window.setInterval(() => setElapsedTime(Math.floor((Date.now() - sessionStartTime) / 1000)), 1000);
    }
    return () => clearInterval(t);
  }, [sessionStartTime]);

  if (showFinished) return (
    <div className="min-h-screen flex items-center justify-center bg-[#050505] p-6 font-orbitron">
      <div className="max-w-md w-full bg-zinc-900 border border-violet-500/30 p-12 rounded-[3rem] text-center shadow-2xl">
        <div className="w-24 h-24 bg-violet-500/10 text-violet-500 rounded-full flex items-center justify-center mx-auto mb-10 text-5xl border border-violet-500/20 shadow-[0_0_30px_rgba(139,92,246,0.2)]">✓</div>
        <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter neon-text">SALIDA REGISTRADA</h2>
