          </div>
          <div className="py-24 bg-black/50 border border-zinc-900 rounded-[3.5rem] shadow-inner mb-14">
            <span className="text-7xl sm:text-9xl font-black font-orbitron text-white tracking-widest tabular-nums drop-shadow-[0_0_20px_rgba(139,92,246,0.4)]">
              {new Date(elapsedTime * 1000).toISOString().substr(11, 8)}
