import React, { useState, useRef, useEffect } from 'react';
import { DocumentType } from './types';
import SignaturePad, { SignaturePadRef } from './components/SignaturePad';
import CameraModal from './components/CameraModal';
import ParticleBackground from './components/ParticleBackground';
import TermsModal from './components/TermsModal';
import ProcessingOverlay from './components/ProcessingOverlay';
import { jsPDF } from 'jspdf';

// === CONFIGURACIÓN DEL CLUB ===
const APP_CONFIG = {
  CLUB_NAME: "SPACE TOWN CLUB",
  RECIPIENT_EMAIL: "appspacetown@gmail.com", 
  EMAILJS: {
    SERVICE_ID: "service_n97bgi4",     
    PUBLIC_KEY: "HHnp6ci-SEnxKhFPA", 
    TEMPLATE_ID: "template_tod2pkl",
  }
};

const LOGO_PNG = "data:image/png;base64,";

declare global {
  interface Window {
    emailjs: any;
  }
}

interface FormState {
  fullName: string;
  documentType: DocumentType | '';
  documentNumber: string;
  artisticName: string;
  selfie?: string; 
  documentFront?: string;
  documentBack?: string;
}

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormState>({
    fullName: '', documentType: DocumentType.CedulaDeCiudadania, documentNumber: '', artisticName: '',
  });
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [isSessionActive, setIsSessionActive] = useState(false);
  const [showFinished, setShowFinished] = useState(false);

  const signaturePadRef = useRef<SignaturePadRef>(null);

  // --- Helpers ---
  const getFullTimestamp = () => new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => resolve(e.target?.result as string);
      reader.readAsDataURL(file);
    });
  };

  const uploadPdfToCloud = async (pdfBlob: Blob): Promise<string> => {
    try {
      const upData = new FormData();
      upData.append('file', pdfBlob, 'registro_spacetown.pdf');
      const res = await fetch('https://tmpfiles.org/api/v1/upload', {
        method: 'POST',
        body: upData
      });
      const json = await res.json();
      return json.status === 'success' ? json.data.url.replace('tmpfiles.org/', 'tmpfiles.org/dl/') : 'N/A';
    } catch (e) {
      return 'Enlace no disponible';
    }
  };

  const applyLegalTemplate = (doc: jsPDF, title: string, page: number) => {
    const w = doc.internal.pageSize.getWidth();
    const h = doc.internal.pageSize.getHeight();
    const margin = 20;
    doc.setDrawColor(139, 92, 246);
    doc.setLineWidth(0.5);
    doc.line(margin - 2, margin, margin - 2, h - margin); 
    doc.setFillColor(250, 250, 255);
    doc.rect(margin, margin, w - (margin * 2), 30, 'F');
    try { doc.addImage(LOGO_PNG, 'PNG', margin + 5, margin + 5, 20, 20); } catch(e) {}
    doc.setTextColor(20, 20, 30);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.text(APP_CONFIG.CLUB_NAME, margin + 30, margin + 15);
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.text("SISTEMA DE SEGURIDAD Y CONTROL VIP", margin + 30, margin + 22);
    doc.setTextColor(139, 92, 246);
    doc.setFontSize(10);
    doc.text(title.toUpperCase(), w - margin - 5, margin + 17, { align: 'right' });
    doc.setFontSize(7);
    doc.setTextColor(150, 150, 150);
    doc.text(`REGISTRO DIGITAL - PÁGINA ${page} - COLOMBIA`, w/2, h - 10, { align: 'center' });
    return margin + 45;
  };

  const handleStartSession = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !signature) {
      alert("⚠️ Por favor complete todos los campos, incluyendo selfie y firma.");
      return;
    }

    setIsProcessing(true);
    setProcessingStep("PROCESANDO REGISTRO VIP...");

    try {
      const doc = new jsPDF();
