      doc.setFontSize(11);
      doc.text("DATOS DEL INVITADO", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 12;

      const info = [
        ["Nombre Completo:", formData.fullName],
        ["Nombre Artístico:", formData.artisticName || "N/A"],
        ["Tipo Documento:", formData.documentType],
        ["Documento ID:", formData.documentNumber],
        ["Fecha y Hora:", getFullTimestamp()]
      ];

      info.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold"); doc.text(label, 25, y);
        doc.setFont("helvetica", "normal"); doc.text(value, 70, y);
        y += 8;
      });

      y += 10;
      doc.setFont("helvetica", "bold"); doc.text("VALIDACIÓN BIOMÉTRICA", 20, y);
      y += 10;
      doc.addImage(formData.selfie, 'JPEG', 25, y, 45, 45);
      if (formData.documentFront) doc.addImage(formData.documentFront, 'JPEG', 75, y, 55, 35);

      doc.addPage();
      y = applyLegalTemplate(doc, "Registro de Ingreso", 2);
      doc.setFont("helvetica", "bold"); doc.text("FIRMA DE RESPONSABILIDAD", 20, y);
      y += 15;
      doc.addImage(signature, 'PNG', 25, y, 60, 25);

      const pdfBlob = doc.output('blob');
      setProcessingStep("ENVIANDO CORREO DE SEGURIDAD...");

      const link = await uploadPdfToCloud(pdfBlob);

      if (window.emailjs) {
        // Se envían todos los campos explícitamente para el template
        await window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `INGRESO VIP: ${formData.fullName}`,
          full_name: formData.fullName,
          id_number: formData.documentNumber,
          artistic_name: formData.artisticName,
          document_type: formData.documentType,
          message: `Nuevo ingreso registrado para ${formData.fullName}. ID: ${formData.documentNumber}.`,
          pdf_link: link
        });
      }

      doc.save(`INGRESO_${formData.fullName.replace(/\s/g, '_')}.pdf`);

      localStorage.setItem('st_club_active', JSON.stringify({ active: true, formData }));
      setIsSessionActive(true);

    } catch (err) {
      console.error(err);
      setIsSessionActive(true);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFinishSession = async () => {
    if (!confirm(`¿Confirmar reporte de salida de ${formData.fullName}?`)) return;

    setIsProcessing(true);
    setProcessingStep("GENERANDO REPORTE DE SALIDA...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Certificado de Salida", 1);

      doc.setFontSize(11);
      doc.text("RESUMEN DE SALIDA", 20, y);
      doc.line(20, y + 2, 190, y + 2);
