        ["INVITADO:", formData.fullName],
        ["DOCUMENTO:", formData.documentNumber],
        ["TIPO:", formData.documentType],
        ["HORA SALIDA:", getFullTimestamp()]
      ];

      report.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold"); doc.text(label, 25, y);
        doc.setFont("helvetica", "normal"); doc.text(value, 80, y);
