import React, { useState, useRef, useEffect } from 'react';
import { DocumentType } from './types';
import SignaturePad, { SignaturePadRef } from './components/SignaturePad';
import CameraModal from './components/CameraModal';
import ParticleBackground from './components/ParticleBackground';
import TermsModal from './components/TermsModal';
import ProcessingOverlay from './components/ProcessingOverlay';
import { jsPDF } from 'jspdf';

// === CONFIGURACIÓN GLOBAL ===
const APP_CONFIG = {
  CLUB_NAME: "SPACE TOWN CLUB",
  RECIPIENT_EMAIL: "appspacetown@gmail.com", 
  EMAILJS: {
    SERVICE_ID: "service_n97bgi4",     
    PUBLIC_KEY: "HHnp6ci-SEnxKhFPA", 
    TEMPLATE_ID: "template_tod2pkl",
  }
};

const LOGO_PNG = "data:image/png;base64,";

declare global {
  interface Window {
    emailjs: any;
  }
}

interface FormState {
  fullName: string;
  documentType: DocumentType | '';
  documentNumber: string;
  artisticName: string;
  selfie?: string; 
  documentFront?: string;
  documentBack?: string;
}

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormState>({
    fullName: '', documentType: DocumentType.CedulaDeCiudadania, documentNumber: '', artisticName: '',
  });
  const [isSigned, setIsSigned] = useState(false);
  const [isCameraModalOpen, setIsCameraModalOpen] = useState(false);
  const [cameraFor, setCameraFor] = useState<'selfie' | 'documentFront' | 'documentBack' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [isSessionActive, setIsSessionActive] = useState(false);
  const [showFinished, setShowFinished] = useState(false);

  const signaturePadRef = useRef<SignaturePadRef>(null);

  // --- Utilidades ---
  const getFullTimestamp = () => new Date().toLocaleString('es-CO', { timeZone: 'America/Bogota' });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (e) => resolve(e.target?.result as string);
      reader.readAsDataURL(file);
    });
  };

  const uploadPdfToCloud = async (pdfBlob: Blob): Promise<string> => {
    try {
      const upData = new FormData();
      upData.append('file', pdfBlob, 'registro_spacetown.pdf');
      const res = await fetch('https://tmpfiles.org/api/v1/upload', {
        method: 'POST',
        body: upData
      });
      const json = await res.json();
      // Formateamos el link para descarga directa
      return json.status === 'success' ? json.data.url.replace('tmpfiles.org/', 'tmpfiles.org/dl/') : 'N/A';
    } catch (e) {
      console.error("Error subiendo PDF:", e);
      return 'Error al generar enlace';
    }
  };

  const applyLegalTemplate = (doc: jsPDF, title: string, page: number) => {
    const w = doc.internal.pageSize.getWidth();
    const h = doc.internal.pageSize.getHeight();
    const margin = 20;
    doc.setDrawColor(139, 92, 246);
    doc.setLineWidth(0.5);
    doc.line(margin - 2, margin, margin - 2, h - margin); 
    doc.setFillColor(250, 250, 255);
    doc.rect(margin, margin, w - (margin * 2), 30, 'F');
    try { doc.addImage(LOGO_PNG, 'PNG', margin + 5, margin + 5, 20, 20); } catch(e) {}
    doc.setTextColor(20, 20, 30);
    doc.setFont("helvetica", "bold");
    doc.setFontSize(14);
    doc.text(APP_CONFIG.CLUB_NAME, margin + 30, margin + 15);
    doc.setFontSize(8);
    doc.setFont("helvetica", "normal");
    doc.text("SISTEMA DE SEGURIDAD Y CONTROL VIP", margin + 30, margin + 22);
    doc.setTextColor(139, 92, 246);
    doc.setFontSize(10);
    doc.text(title.toUpperCase(), w - margin - 5, margin + 17, { align: 'right' });
    doc.setFontSize(7);
    doc.setTextColor(150, 150, 150);
    doc.text(`REGISTRO DIGITAL OFICIAL - PÁGINA ${page}`, w/2, h - 10, { align: 'center' });
    return margin + 45;
  };

  // --- PROCESO DE INGRESO ---
  const handleStartSession = async (e: React.FormEvent) => {
    e.preventDefault();
    const signature = signaturePadRef.current?.getSignature();

    if (!formData.fullName || !formData.documentNumber || !formData.selfie || !signature) {
      alert("⚠️ Error: Debe completar todos los campos, capturar su selfie y firmar el registro.");
      return;
    }

    setIsProcessing(true);
    setProcessingStep("GENERANDO EXPEDIENTE VIP...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Registro de Ingreso", 1);

      doc.setFontSize(11);
      doc.text("INFORMACIÓN DEL INVITADO", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 12;

      const info = [
        ["Nombre Completo:", formData.fullName],
        ["Nombre Artístico:", formData.artisticName || "N/A"],
        ["Tipo de Documento:", formData.documentType],
        ["Documento de Identidad:", formData.documentNumber],
        ["Fecha de Ingreso:", getFullTimestamp()]
      ];

      info.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold"); doc.text(label, 25, y);
        doc.setFont("helvetica", "normal"); doc.text(value, 80, y);
        y += 8;
      });

      y += 10;
      doc.setFont("helvetica", "bold"); doc.text("EVIDENCIA BIOMÉTRICA", 20, y);
      y += 10;
      doc.addImage(formData.selfie, 'JPEG', 25, y, 50, 50);
      if (formData.documentFront) doc.addImage(formData.documentFront, 'JPEG', 85, y, 60, 40);

      doc.addPage();
      y = applyLegalTemplate(doc, "Registro de Ingreso", 2);
      doc.setFont("helvetica", "bold"); doc.text("FIRMA DIGITAL DEL INVITADO", 20, y);
      y += 15;
      doc.addImage(signature, 'PNG', 25, y, 70, 30);

      const pdfBlob = doc.output('blob');

      // 1. Descarga local para el usuario
      doc.save(`INGRESO_SPACETOWN_${formData.fullName.replace(/\s/g, '_')}.pdf`);

      // 2. Subida a la nube para obtener el link
      setProcessingStep("NOTIFICANDO A ADMINISTRACIÓN...");
      const link = await uploadPdfToCloud(pdfBlob);

      // 3. Envío por EmailJS con todos los datos
      if (window.emailjs) {
        await window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `NUEVO INGRESO: ${formData.fullName}`,
          full_name: formData.fullName,
          id_number: formData.documentNumber,
          artistic_name: formData.artisticName || "N/A",
          document_type: formData.documentType,
          message: `Acceso concedido a ${formData.fullName}. ID: ${formData.documentNumber}.`,
          pdf_link: link
        });
      }

      localStorage.setItem('st_club_active', JSON.stringify({ active: true, formData }));
      setIsSessionActive(true);

    } catch (err) {
      console.error("Fallo en protocolo de ingreso:", err);
      alert("Error en el envío. El registro se activará localmente.");
      setIsSessionActive(true);
    } finally {
      setIsProcessing(false);
    }
  };

  // --- PROCESO DE SALIDA ---
  const handleFinishSession = async () => {
    if (!confirm(`¿Desea reportar la salida oficial de ${formData.fullName}?`)) return;

    setIsProcessing(true);
    setProcessingStep("EXPIDIENDO CERTIFICADO DE SALIDA...");

    try {
      const doc = new jsPDF();
      let y = applyLegalTemplate(doc, "Reporte de Salida", 1);

      doc.setFontSize(11);
      doc.text("DETALLES DE FINALIZACIÓN", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 15;

      const report = [
        ["NOMBRE COMPLETO:", formData.fullName],
        ["IDENTIFICACIÓN:", formData.documentNumber],
        ["TIPO DE DOCUMENTO:", formData.documentType],
        ["FECHA Y HORA SALIDA:", getFullTimestamp()]
      ];

      report.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold"); doc.text(label, 25, y);
        doc.setFont("helvetica", "normal"); doc.text(value, 80, y);
        y += 10;
      });

      doc.setFillColor(245, 245, 250);
      doc.rect(20, y + 10, 170, 25, 'F');
      doc.text("SISTEMA SPACE TOWN: SALIDA CONFIRMADA", 105, y + 25, { align: 'center' });

      const pdfBlob = doc.output('blob');

      // Descarga local de salida
      doc.save(`SALIDA_SPACETOWN_${formData.fullName.replace(/\s/g, '_')}.pdf`);

      setProcessingStep("SINCRONIZANDO SALIDA...");
      const link = await uploadPdfToCloud(pdfBlob);

      if (window.emailjs) {
        await window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          subject: `SALIDA REGISTRADA: ${formData.fullName}`,
          full_name: formData.fullName,
          id_number: formData.documentNumber,
          message: `El invitado ${formData.fullName} ha abandonado las instalaciones de forma oficial.`,
          pdf_link: link
        });
      }

    } catch (e) {
      console.error("Error en reporte de salida:", e);
    } finally {
      localStorage.removeItem('st_club_active');
      setIsProcessing(false);
      setShowFinished(true);
      setIsSessionActive(false);
    }
  };

  const resetAll = () => {
    localStorage.removeItem('st_club_active');
    setShowFinished(false);
    setIsSessionActive(false);
    setFormData({ fullName: '', documentType: DocumentType.CedulaDeCiudadania, documentNumber: '', artisticName: '', });
    setTermsAccepted(false);
    setIsSigned(false);
  };

  useEffect(() => {
    const saved = localStorage.getItem('st_club_active');
    if (saved) {
      try {
        const data = JSON.parse(saved);
        if (data.active) {
          setIsSessionActive(true);
          setFormData(data.formData);
          setTermsAccepted(true);
        }
      } catch (e) { localStorage.removeItem('st_club_active'); }
    }
    if (window.emailjs) window.emailjs.init(APP_CONFIG.EMAILJS.PUBLIC_KEY);
  }, []);

  // --- VISTAS ---

  if (showFinished) return (
    <div className="min-h-screen flex items-center justify-center bg-[#050505] p-6 font-orbitron">
      <div className="max-w-md w-full bg-zinc-900 border border-violet-500/30 p-12 rounded-[3rem] text-center shadow-2xl relative">
        <div className="w-24 h-24 bg-violet-500/10 text-violet-500 rounded-full flex items-center justify-center mx-auto mb-10 text-5xl border border-violet-500/20 shadow-[0_0_30px_rgba(139,92,246,0.2)]">✓</div>
        <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter neon-text">OPERACIÓN EXITOSA</h2>
        <p className="text-zinc-500 text-[10px] mb-12 tracking-[0.3em] uppercase font-bold leading-relaxed">El reporte ha sido generado y enviado a seguridad.</p>
        <button onClick={resetAll} className="w-full py-6 bg-white text-black font-black rounded-2xl uppercase text-[11px] tracking-[0.3em] hover:bg-violet-600 hover:text-white transition-all transform hover:scale-105 active:scale-95 shadow-xl">Nuevo Registro</button>
      </div>
    </div>
  );

  if (isSessionActive) return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      <div className="min-h-screen flex flex-col items-center justify-center p-6 text-center">
        <div className="max-w-2xl w-full bg-zinc-950/70 border border-violet-500/20 p-12 rounded-[4.5rem] backdrop-blur-3xl shadow-2xl">
          <div className="mb-10">
            <h2 className="text-4xl font-black font-orbitron text-white mb-3 tracking-tighter neon-text">VIP ACTIVO</h2>
            <div className="w-24 h-1 bg-violet-600 mx-auto mb-8 rounded-full shadow-[0_0_20px_#8b5cf6]"></div>
            <p className="text-[16px] text-white font-black tracking-[0.2em] uppercase mb-2">{formData.fullName}</p>
            <p className="text-[10px] text-violet-400 font-bold tracking-[0.4em] uppercase opacity-80">
              {formData.documentType}: {formData.documentNumber}
            </p>
          </div>

          <div className="py-24 px-10 bg-black/40 border border-zinc-900 rounded-[3.5rem] mb-14 shadow-inner relative overflow-hidden group">
             <div className="absolute inset-0 bg-violet-600/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
             <div className="text-violet-500 text-6xl mb-8 animate-pulse">✦</div>
             <p className="text-white text-[12px] font-black uppercase tracking-[0.5em] leading-loose">
               Acceso Validado.<br/>Has ingresado a Space Town Club.<br/>Disfruta la noche.
             </p>
          </div>

          <button 
            onClick={handleFinishSession} 
            className="w-full py-8 bg-red-600 text-white font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.4em] text-[12px] hover:bg-red-500 transition-all shadow-2xl active:scale-95 border border-red-500/50"
          >
            Reportar Salida y Cerrar Cuenta
          </button>
        </div>
      </div>
    </>
  );

  return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      {!termsAccepted ? <TermsModal onAccept={() => setTermsAccepted(true)} /> : (
        <div className="min-h-screen flex items-center justify-center p-4 sm:p-10">
          <div className="max-w-4xl w-full bg-zinc-950/80 border border-zinc-900 p-8 sm:p-20 rounded-[5rem] shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-64 h-64 bg-violet-600/5 blur-[100px] rounded-full"></div>
            <header className="text-center mb-16">
              <h1 className="text-5xl sm:text-7xl font-black font-orbitron text-white uppercase tracking-tighter neon-text">{APP_CONFIG.CLUB_NAME}</h1>
              <p className="text-[10px] text-zinc-500 font-bold tracking-[0.8em] uppercase mt-6">Protocolo de Acceso VIP</p>
            </header>
            <form onSubmit={handleStartSession} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Completo</label>
                  <input type="text" value={formData.fullName} onChange={e => setFormData({...formData, fullName: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="NOMBRE Y APELLIDOS" required />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Nombre Artístico</label>
                  <input type="text" value={formData.artisticName} onChange={e => setFormData({...formData, artisticName: e.target.value.toUpperCase()})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all" placeholder="ALIAS (OPCIONAL)" />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-zinc-600 uppercase tracking-[0.3em] ml-2">Tipo de Documento</label>
                  <select value={formData.documentType} onChange={e => setFormData({...formData, documentType: e.target.value as DocumentType})} className="w-full px-7 py-5 bg-zinc-900/50 border border-zinc-800 text-white rounded-2xl font-bold uppercase focus:border-violet-600 outline-none transition-all cursor-pointer">
                    {Object.values(DocumentType).map(t => <option key={t} value={t} className="bg-zinc-900">{t}</option>)}
                  </select>
                </div>
