      doc.setFontSize(11);
      doc.text("DATOS DEL ARTISTA", 20, y);
      doc.line(20, y + 2, 190, y + 2);
      y += 12;

      const info = [
        ["Nombre Completo:", formData.fullName],
        ["Nombre Artístico:", formData.artisticName || "N/A"],
        ["Identificación:", formData.documentNumber],
        ["Fecha Ingreso:", getFullTimestamp()]
      ];

      info.forEach(([label, value]) => {
        doc.setFont("helvetica", "bold"); doc.text(label, 25, y);
        doc.setFont("helvetica", "normal"); doc.text(value, 80, y);
        y += 8;
      });

      y += 10;
      doc.setFont("helvetica", "bold"); doc.text("VALIDACIÓN VISUAL", 20, y);
      y += 10;
      // Comprimimos un poco las imágenes para que el PDF pese menos y suba más rápido
      doc.addImage(formData.selfie, 'JPEG', 25, y, 45, 45, undefined, 'FAST');
      if (formData.documentFront) doc.addImage(formData.documentFront, 'JPEG', 80, y, 55, 35, undefined, 'FAST');

      doc.addPage();
      y = applyLegalTemplate(doc, "Registro de Ingreso", 2);
      doc.setFont("helvetica", "bold"); doc.text("FIRMA DIGITAL", 20, y);
      y += 15;
      doc.addImage(signature, 'PNG', 25, y, 60, 25);

      const pdfBlob = doc.output('blob');

      // 1. DESCARGA INMEDIATA
      doc.save(`VIP_${formData.documentNumber}.pdf`);

      // 2. SUBIDA CON TIEMPO LÍMITE (Para no trabar la app)
      setProcessingStep("SINCRONIZANDO CON NUBE...");
      const link = await uploadPdfToCloud(pdfBlob);

      // 3. ENVÍO A EMAILJS (Variables exactas de tu captura)
      setProcessingStep("FINALIZANDO NOTIFICACIÓN...");
      if (window.emailjs) {
        await window.emailjs.send(APP_CONFIG.EMAILJS.SERVICE_ID, APP_CONFIG.EMAILJS.TEMPLATE_ID, {
          to_email: APP_CONFIG.RECIPIENT_EMAIL,
          // Mapeo según tu captura:
          full_name: formData.fullName,
          doc_number: formData.documentNumber,
          artistic_name: formData.artisticName || "N/A",
          download_link: link,
          pdf_link: link,
          name: formData.fullName,
          message: `Ingreso validado para ${formData.fullName}.`
        });
      }

      localStorage.setItem('st_club_active', JSON.stringify({ active: true, formData }));
      setIsSessionActive(true);

    } catch (err) {
      console.error("Error en proceso:", err);
      // Si falla cualquier cosa externa, permitimos que el usuario entre porque el PDF ya se descargó
      setIsSessionActive(true);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFinishSession = async () => {
    if (!confirm(`¿Confirmar salida oficial de ${formData.fullName}?`)) return;

    setIsProcessing(true);
    setProcessingStep("EXPIDIENDO CERTIFICADO...");

