          <button onClick={handleFinishSession} className="w-full py-8 bg-red-600 text-white font-black font-orbitron rounded-[2.5rem] uppercase tracking-[0.4em] text-[12px] hover:bg-red-500 transition-all shadow-2xl active:scale-95 border border-red-500/50">Cerrar Registro y Salir</button>
        </div>
      </div>
    </>
  );

  return (
    <>
      <ParticleBackground />
      {isProcessing && <ProcessingOverlay step={processingStep} />}
      {!termsAccepted ? <TermsModal onAccept={() => setTermsAccepted(true)} /> : (
        <div className="min-h-screen flex items-center justify-center p-4 sm:p-10">
